/**
 * Generate document_template test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateDocumentTemplateTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateDocumentTemplateTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateDocumentTemplateTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<DocumentTemplateCreateRequest> = {}
): DocumentTemplateCreateRequest {
  let baseData: DocumentTemplateCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalDocumentTemplateFixture };
      break;

    case 'complete':
      baseData = { ...completeDocumentTemplateFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidDocumentTemplateFixture } as DocumentTemplateCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueDocumentTemplateFixture,
        name: `Test DocumentTemplate ${generateUniqueId()}`,
      };
      break;

    default:
      baseData = { ...completeDocumentTemplateFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple document_template fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultipleDocumentTemplateFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultipleDocumentTemplateFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `DocumentTemplate #${index + 1}`,
 * }));
 * ```
 */
export function generateMultipleDocumentTemplateFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: DocumentTemplateCreateRequest, index: number) => DocumentTemplateCreateRequest
): DocumentTemplateCreateRequest[] {
  const fixtures: DocumentTemplateCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generateDocumentTemplateTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test DocumentTemplate ${generateUniqueId()}-${i}`;
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

